const tg = $input.first().json;
const msg = tg.message || tg.edited_message;
if (!msg) return [];
const text = (msg.text || msg.caption || '').trim();
if (!text || (msg.from && msg.from.is_bot)) return [];
const from = msg.from || {};
return [{ json: {
  tg_chat_id: String(msg.chat.id),
  message_text: text,
  name: [from.first_name, from.last_name].filter(Boolean).join(' ') || 'Гость',
  language: from.language_code || 'ru'
}}];

const ctx = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const extracted = $('📝 Извлечь').first().json;
const msg = extracted.message_text;

// Season awareness
const month = new Date().getMonth() + 1;
const monthName = new Date().toLocaleDateString('ru-RU', {month: 'long', year: 'numeric'});
const isSimilanOpen = month >= 11 || month <= 4;
const isHighSeason = month >= 11 || month <= 4;
const seasonStatus = isSimilanOpen
  ? 'Симиланские острова ОТКРЫТЫ — отличное время для снорклинга!'
  : 'Симиланские острова ЗАКРЫТЫ до ноября (нацпарк закрыт летом). Предлагай Пхи-Пхи, Джеймс Бонд, Ко Лан.';

// Build client memory block
const lines = [];
lines.push(`Текущая дата: ${monthName}, ${isHighSeason ? 'высокий сезон' : 'зелёный сезон'}`);
lines.push(`Симилан: ${isSimilanOpen ? 'ОТКРЫТЫ ✅' : 'ЗАКРЫТЫ ⛔ (до ноября)'}`);
if (ctx && ctx.client_name) lines.push(`Имя: ${ctx.client_name}`);
if (ctx && ctx.client_stage && ctx.client_stage !== 'new') lines.push(`Стадия: ${ctx.client_stage}`);
if (ctx && ctx.client_country) lines.push(`Откуда: ${ctx.client_country}`);
if (ctx && ctx.interests && ctx.interests.length) lines.push(`Интересы: ${ctx.interests.join(', ')}`);
if (ctx && ctx.budget_level && ctx.budget_level !== 'medium') lines.push(`Бюджет: ${ctx.budget_level}`);
if (ctx && ctx.travel_style) lines.push(`Стиль: ${ctx.travel_style}`);
if (ctx && ctx.arrival_date) lines.push(`Дата приезда: ${ctx.arrival_date}`);
if (ctx && ctx.group_size) lines.push(`Группа: ${ctx.group_size} чел.`);
if (ctx && ctx.has_children) lines.push('Едут с детьми: да');
if (ctx && ctx.last_tour_viewed) lines.push(`Последний тур: ${ctx.last_tour_viewed}`);
if (ctx && ctx.tours_booked && ctx.tours_booked.length) lines.push(`Забронировал: ${ctx.tours_booked.join(', ')}`);
const clientMemory = lines.join('\n');

// Build conversation history
let lastConvs = 'Первое обращение.';
try {
  let convs = (ctx && ctx.last_conversations) || [];
  if (typeof convs === 'string') convs = JSON.parse(convs);
  if (Array.isArray(convs) && convs.length) {
    lastConvs = convs
      .filter(c => c && (c.msg || c.message))
      .slice(0, 8)
      .reverse()
      .map(c => `Клиент: ${c.msg||c.message||''}\nКотЭ: ${c.res||c.response||''}`)
      .join('\n---\n');
  }
} catch(e) { lastConvs = 'История недоступна.'; }

return [{ json: {
  tg_chat_id: extracted.tg_chat_id,
  message_text: msg,
  client_id: ctx ? ctx.client_id : null,
  client_name: ctx ? ctx.client_name : null,
  client_stage: (ctx && ctx.client_stage) || 'new',
  is_new_client: (ctx && ctx.is_new_client) || false,
  client_memory: clientMemory,
  last_conversations: lastConvs,
  similan_open: isSimilanOpen
}}];

